ults\n2. dim_constructors\n\n## Output Columns\n\n1. season\n2. constructor id\n3. constructor name\n4. nationality\n5. race starts\n6. total points\n7. number of wins\n8. number of podiums\n9. standing position","commandVersion":13,"state":"input","results":null,"resultDbfsStatus":"INLINED_IN_TREE","resultDbfsErrorMessage":null,"errorSummary":null,"errorTraceType":null,"error":null,"errorDetails":null,"baseErrorDetails":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"latestAssumeRoleInfo":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"metadata":{},"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultIndex":null,"listResultMetadata":[],"subcommandOptions":null,"contentSha256Hex":null,"tableResultSettingsMap":{},"nuid":"291db38c-d350-4bb7-823b-f7549148404f"},{"version":"CommandV1","origId":4797249454757947,"guid":"ab04ee70-7370-4fde-8341-178a6f709fd3","subtype":"command","commandType":"auto","position":1.25,"command":"%md\n![](../04-gold/Untitled.png)","commandVersion":3,"state":"input","results":null,"resultDbfsStatus":"INLINED_IN_TREE","resultDbfsErrorMessage":null,"errorSummary":null,"errorTraceType":null,"error":null,"errorDetails":null,"baseErrorDetails":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"latestAssumeRoleInfo":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"metadata":{},"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultIndex":null,"listResultMetadata":[],"subcommandOptions":null,"contentSha256Hex":null,"tableResultSettingsMap":{},"nuid":"8d403f73-7816-46d7-bc3f-0545117bbd74"},{"version":"CommandV1","origId":4797249454757945,"guid":"71404363-8bd0-4b2b-9fd3-1d9d14be2b38","subtype":"command","commandType":"auto","position":2.0,"command":"create or replace view formula1.gold.v_constructors_standing AS\nWITH driver_season_aggregates AS (\n    SELECT \n        r.season AS season,\n        d.constructor_id AS constructor_id,\n        d.constructor_name AS constructor_name,\n        d.nationality AS nationality,\n        COUNT(*) AS race_starts,\n        SUM(r.points) AS total_points,\n        COUNT_IF(r.is_win) AS number_of_wins,\n        COUNT_IF(r.is_podium) AS number_of_podiums\n    FROM formula1.gold.fact_session_results AS r\n    JOIN formula1.gold.dim_constructors AS d\n        ON d.constructor_id = r.constructor_id\n    GROUP BY \n        r.season,\n        d.constructor_id,\n        d.constructor_name,\n        d.nationality\n)\n\nSELECT\n    RANK() OVER (\n        PARTITION BY season \n        ORDER BY total_points DESC, number_of_wins DESC\n    ) AS standing_position,\n    season,\n    constructor_id,\n    constructor_name,\n    nationality,\n    race_starts,\n    total_points,\n    number_of_wins,\n    number_of_podiums\nFROM driver_season_aggregates\nORDER BY \n    season DESC, \n    standing_position ASC;","commandVersion":156,"state":"finished","results":{"type":"listResults","data":[{"type":"mimeBundle","data":{"application/vnd.databricks.empty-table+json":{"directive_name":"CreateView"}}